  ('dietitian-moex-09054', 'dietitian', 'dietitian-moex-097-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '下列何者為廚房與清潔區之空氣污染指標？', '["氧氣消耗量", "氧氣殘餘量", "二氧化碳消耗量", "二氧化碳殘餘量"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:52+00:00", "source_pdf_sha1": "3f49438bcf6e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097140", "c": "113", "s": "4001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "097", "exam_name": "097年第二次專技醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試、法醫師考試", "original_question_number": 20, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
